import{_ as t,a as s,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as a,o as l,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Utiliser le blog","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/blog.md","filePath":"fr-FR/Other/blog.md","lastUpdated":1781962217000}'),n={name:"fr-FR/Other/blog.md"};function d(c,e,p,u,g,h){return l(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="utiliser-le-blog" tabindex="-1">Utiliser le blog <a class="header-anchor" href="#utiliser-le-blog" aria-label="Permalink to &quot;Utiliser le blog&quot;">​</a></h1><p>La fonction Blog ajoute une page de blog indépendante à votre site ImgBed.</p><p>Une fois activée, les visiteurs peuvent y accéder depuis :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Page d’accueil du blog" loading="lazy"></p><p>Le blog est adapté du projet open source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed le réintègre en Vue afin qu’il fonctionne directement dans le site d’hébergement.</p><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; Blog</span></span></code></pre></div><p><img src="'+s+'" alt="Paramètres du blog" loading="lazy"></p><h2 id="premiere-utilisation" tabindex="-1">Première utilisation <a class="header-anchor" href="#premiere-utilisation" aria-label="Permalink to &quot;Première utilisation&quot;">​</a></h2><ol><li>Activez l’option <code>Activer</code>.</li><li>Sélectionnez le compte GitHub qui stockera la configuration du blog.</li><li>Cliquez sur <code>Mettre à jour le blog</code>.</li><li>Attendez le message de réussite.</li><li>Ouvrez <code>https://votre-domaine/blog/</code> pour vérifier le résultat.</li></ol><p>Lors de la première utilisation, ImgBed prépare un dépôt privé dans le compte GitHub sélectionné :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Ce dépôt contient la configuration du blog et le contenu des articles.</p><h2 id="rediger-des-articles" tabindex="-1">Rédiger des articles <a class="header-anchor" href="#rediger-des-articles" aria-label="Permalink to &quot;Rédiger des articles&quot;">​</a></h2><p>Les articles se modifient dans votre dépôt privé GitHub :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Flux habituel :</p><ol><li>Ouvrez GitHub.</li><li>Entrez dans le dépôt <code>imgbed-blog-config</code>.</li><li>Créez ou modifiez les fichiers d’articles.</li><li>Enregistrez les changements avec un commit.</li><li>Revenez dans l’administration ImgBed et cliquez sur <code>Mettre à jour le blog</code>. Vous pouvez aussi cliquer trois fois sur le logo en haut à gauche de la page du blog pour déclencher une mise à jour.</li></ol><p><code>Mettre à jour le blog</code> n’écrase pas les articles existants. Cette action sert surtout à initialiser le dépôt ou à rafraîchir le cache.</p><h2 id="fonctions-disponibles" tabindex="-1">Fonctions disponibles <a class="header-anchor" href="#fonctions-disponibles" aria-label="Permalink to &quot;Fonctions disponibles&quot;">​</a></h2><p>Le blog prend en charge la liste des articles, les catégories, les tags, les archives, la recherche, le mode sombre et le changement de langue.</p><p>Les commentaires et les statistiques de visites sont également disponibles.</p><p><img src="'+i+'" alt="Commentaires du blog" loading="lazy"></p><p>Les commentaires s’affichent sous les articles. Les visiteurs peuvent renseigner un avatar, un pseudo, une adresse e-mail et le contenu du commentaire.</p><p>Les statistiques indiquent les vues des articles et les visites du site, ce qui aide à suivre l’activité du blog.</p><h2 id="adresse-d-acces" tabindex="-1">Adresse d’accès <a class="header-anchor" href="#adresse-d-acces" aria-label="Permalink to &quot;Adresse d’accès&quot;">​</a></h2><p>Le blog est toujours publié sous <code>/blog/</code>.</p><p>Si votre domaine ImgBed est :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>l’adresse du blog sera :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Si vous désactivez le blog, les visiteurs ne pourront plus accéder à cette page.</p>',33)])])}const f=a(n,[["render",d]]);export{v as __pageData,f as default};
